head.script:
// 세션정보 가져오기
scwin.sUserId       = $c.data.getMemInfo("userId") == null ? "" : $c.data.getMemInfo("userId");   
scwin.sUserClsCd    = $c.data.getMemInfo("userClsCd") == null ? "" : $c.data.getMemInfo("userClsCd");   
scwin.sClntNo       = $c.data.getMemInfo("clntNo") == null ? "" : $c.data.getMemInfo("clntNo");   //거래처번호
scwin.sClntNm       = $c.data.getMemInfo("clntNm") == null ? "" : $c.data.getMemInfo("clntNm");   //거래처이름

scwin.strFromDate   = $c.date.getServerDateTime("yyyyMMdd").substring(0,8);   // 현재년월일을 구한다.
scwin.strToDate     = $c.date.getServerDateTime("yyyyMMdd");  	// 현재일자를 구한다.
scwin.strDate = scwin.strFromDate + scwin.strToDate;

//parameter
scwin.params = $c.data.getParameter();       
scwin.odrNo              = scwin.params.odrNo == null ? "" : scwin.params.odrNo;
scwin.mrn                = scwin.params.mrn == null ? "" : scwin.params.mrn;
scwin.msn                = scwin.params.msn == null ? "" : scwin.params.msn;
scwin.hsn                = scwin.params.hsn == null ? "" : scwin.params.hsn;
scwin.blNo               = scwin.params.blNo == null ? "" : scwin.params.blNo;
scwin.wrkPlCd            = scwin.params.wrkPlCd == null ? "" : scwin.params.wrkPlCd;
scwin.wrkPlNm            = scwin.params.wrkPlNm == null ? "" : scwin.params.wrkPlNm;
scwin.crryinoutTermFrom  = scwin.params.crryinoutTermFrom == null ? "" : scwin.params.crryinoutTermFrom;
scwin.crryinoutTermTo    = scwin.params.crryinoutTermTo == null ? "" : scwin.params.crryinoutTermTo;
scwin.crryinoutCls       = scwin.params.crryinoutCls == null ? "" : scwin.params.crryinoutCls;
scwin.gateInOut          = scwin.params.gateInOut == null ? "" : scwin.params.gateInOut;
scwin.cntrBulk           = scwin.params.cntrBulk == null ? "" : scwin.params.cntrBulk;

scwin.onpageload = function() {
    if ("" != scwin.wrkPlCd) {  //다른 페이지에서 넘어왔을 때
        scwin.f_OpenRetrieve();
    }	

    const codeOptions = [ 
        { grpCd : "OP197", compID : "acb_crryinoutCls" },
        { grpCd : "OP121", compID : "acb_sndCls" }
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {

    ed_crryinoutTermFrom.setValue("20050101");
    ed_crryinoutTermTo.setValue(scwin.strFromDate);
    //ed_wrkPlCd.focus();
};



scwin.udc_comCode_onclickEvent = function (e) {
    udc_wrkPlCode.cfCommonPopUp(
                                scwin.udc_comCode_callBackFunc,
                                ed_wrkPlCd.getValue(),
                                ed_wrkPlNm.getValue(),
                                "F" // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                , null // Title순서
                                , null // 보여주는 각 컬럼들의 폭
                                , null // 컬럼중에서 숨기는 컬럼 지정
                                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                                , null // POP-UP뛰을때 원도우의 사용자 정의 높이
                                , null // 윈도우 위치 Y좌표
                                , null // 윈도우 위치 X좌표
                                , null // 중복체크여부 ("F")
                                , "T" // 전체검색허용여부 ("F")
                                , "작업장,작업장코드,작업장명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );

};

scwin.udc_comCode_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret, ed_wrkPlCd, ed_wrkPlNm);
};


scwin.udc_comCode_onviewchangeNameEvent = function (info) {
    if(ed_wrkPlNm.getValue() === "") {
        ed_wrkPlCd.setValue("");
    } else {
        udc_wrkPlCode.cfCommonPopUp(
                                scwin.udc_comCode_callBackFunc,
                                ed_wrkPlCd.getValue(),
                                ed_wrkPlNm.getValue(),
                                "T" // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                , null // Title순서
                                , null // 보여주는 각 컬럼들의 폭
                                , null // 컬럼중에서 숨기는 컬럼 지정
                                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                                , null // POP-UP뛰을때 원도우의 사용자 정의 높이
                                , null // 윈도우 위치 Y좌표
                                , null // 윈도우 위치 X좌표
                                , null // 중복체크여부 ("F")
                                , "T" // 전체검색허용여부 ("F")
                                , "작업장,작업장코드,작업장명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );
    }
};

scwin.udc_comCode_onblurCodeEvent = function (e) {
    if(ed_wrkPlCd.getValue() === "") {
        ed_wrkPlNm.setValue("");
    } else {
        udc_wrkPlCode.cfCommonPopUp(
                                scwin.udc_comCode_callBackFunc,
                                ed_wrkPlCd.getValue(),
                                ed_wrkPlNm.getValue(),
                                "T" // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                , null // Title순서
                                , null // 보여주는 각 컬럼들의 폭
                                , null // 컬럼중에서 숨기는 컬럼 지정
                                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                                , null // POP-UP뛰을때 원도우의 사용자 정의 높이
                                , null // 윈도우 위치 Y좌표
                                , null // 윈도우 위치 X좌표
                                , null // 중복체크여부 ("F")
                                , "T" // 전체검색허용여부 ("F")
                                , "작업장,작업장코드,작업장명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );
    }
};


//-------------------------------------------------------------------------
// 세관반출입현황에서 조회
//-------------------------------------------------------------------------
scwin.f_OpenRetrieve = function() {

    ed_wrkPlCd.setValue(scwin.wrkPlCd);
    ed_wrkPlNm.setValue(scwin.wrkPlNm);
    ed_mrn.setValue(scwin.mrn);
    ed_msn.setValue(scwin.msn);
    ed_hsn.setValue(scwin.hsn);
    ed_blNo.setValue(scwin.blNo);
    ed_odrNo.setValue(scwin.odrNo);
    ed_crryinoutTermFrom.setValue(scwin.crryinoutTermFrom);
    ed_crryinoutTermTo.setValue(scwin.crryinoutTermTo);
    acb_crryinoutCls.setValues(scwin.crryinoutCls);

    dma_retrieve.set("wrkPl", ed_wrkPlCd.getValue());
    dma_retrieve.set("crryinoutTermFrom", ed_crryinoutTermFrom.getValue());
    dma_retrieve.set("crryinoutTermTo", ed_crryinoutTermTo.getValue());
    dma_retrieve.set("mrn", ed_mrn.getValue());
    dma_retrieve.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
    dma_retrieve.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
    dma_retrieve.set("odrNo", ed_odrNo.getValue());
    dma_retrieve.set("blNo", ed_blNo.getValue());
    dma_retrieve.set("cntrBulk", scwin.cntrBulk);
    dma_retrieve.set("gateInOut", scwin.gateInOut);

    if(dma_retrieve.get("crryinoutCls") == "all") {
        dma_retrieve.set("crryinoutCls", "");
    } else {
        dma_retrieve.set("crryinoutCls", acb_crryinoutCls.getValue());
    }

    if(dma_retrieve.get("sndClsCd") == "all") {
        dma_retrieve.set("sndClsCd", "");
    } else {
        dma_retrieve.set("sndClsCd", acb_sndCls.getValue());
    }

    $c.sbm.execute(sbm_retrieve);

};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {   
    let chkwrkplcd = ed_wrkPlCd.getValue();
    if($c.gus.cfIsNull(chkwrkplcd)){
        await $c.win.alert("작업장 코드는 필수 입력 항목입니다.");
        ed_wrkPlCd.focus();
        return;
    }

    // 필수항목 체크
    let chk11 = await $c.gus.cfValidate([tb_queryList]);
    if (!chk11) {return false;}

    if (!$c.gus.cfIsAfterDate(ed_crryinoutTermFrom.getValue(), ed_crryinoutTermTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_srchWrkStDt.focus();
        return;
    }

    var cheVal = "";

    if (ckWrkPlCd.checked) {
        cheVal = "1";

    } else {
        cheVal = "0";
    }

    // dma_retrieve.set("wrkPl", ed_wrkPlCd.getValue());
    dma_retrieve.set("wrkPl", ed_wrkPlCd.getValue());
    dma_retrieve.set("crryinoutTermFrom", ed_crryinoutTermFrom.getValue());
    dma_retrieve.set("crryinoutTermTo", ed_crryinoutTermTo.getValue());
    dma_retrieve.set("mrn", ed_mrn.getValue());
    dma_retrieve.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
    dma_retrieve.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
    dma_retrieve.set("ckWrkPlCd", cheVal);
    dma_retrieve.set("blNo", ed_blNo.getValue());
    dma_retrieve.set("cntrBulk", scwin.cntrBulk);

    debugger;
    if(dma_retrieve.get("crryinoutCls") == "all") {
        dma_retrieve.set("crryinoutCls", "");
    } else {
        dma_retrieve.set("crryinoutCls", acb_crryinoutCls.getValue());
    }

    if(dma_retrieve.get("sndClsCd") == "all") {
        dma_retrieve.set("sndClsCd", "");
    } else {
        dma_retrieve.set("sndClsCd", acb_sndCls.getValue());
    }

    $c.sbm.execute(sbm_retrieve);
};


//-------------------------------------------------------------------------
// 조회 조건 Reset
//-------------------------------------------------------------------------
scwin.f_Reset = function() {
    $c.gus.cfInitObjects([tb_queryList]);

    ed_crryinoutTermFrom.setValue("20250101");
    ed_crryinoutTermTo.setValue(scwin.strFromDate);
};


//-------------------------------------------------------------------------
// 닫기
//-------------------------------------------------------------------------
scwin.f_Close = function() {
    $c.win.closePopup();
};


//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.f_Trans = function() {
    return null;
};



scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        //$c.gus.cfShowError(sbm_retrieve);
        return;
    }
    if(ds_emp.getRowCount()==0){
        $c.gus.cfAlertMsg(MSG_CM_WRN_002,[""]);  //alert("조회된 데이터가 없습니다.");
    }
    totalRows.setValue(ds_emp.getRowCount());

    //asis에서 체크를 전부 풀고 있어서 똑같이 적용 함 
    gr_emp.checkAll("sndYn", false);
};

scwin.sbm_saveEmp_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.win.alert(sbm_saveEmp.ErrorMsg);
        return;
    }

    $c.gus.cfAlertMsg(MSG_CM_INF_001,[""]);
    totalRows.setValue(ds_emp.getRowCount());

    if(ds_emp.getRowCount() == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_WRN_002,[""]);  //alert("조회된 데이터가 없습니다.");
	}

	//$c.gus.cfGoPrevPosition(ds_emp, pos_groupCode);
};

scwin.gr_emp_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) return;

    if(columnId == "sndYn"){
        $c.win.alert("ds_emp.getCellData(sndYn) : " + ds_emp.getCellData(rowIndex, "sndYn"));
        debugger;
        if(ds_emp.getCellData(rowIndex, "sndYn") == 1 && ds_emp.getCellData(rowIndex, "sndClsCdNm") != "미전송"){
            $c.win.alert("전송완료된 데이타는 수정할 수 없습니다.");
            ds_emp.setCellData(rowIndex, "sndYn", 1);
            return;
        }
    }
    //반입
    if(ds_emp.getCellData(rowIndex,"crryinoutClsCd") == "I"){       
        scwin.f_Detail(rowIndex, "op_302_01_16b.xml");


        //반출
    } else if(ds_emp.getCellData(rowIndex,"crryinoutClsCd") == "O"){ 
        scwin.f_Detail(rowIndex, "op_302_01_17b.xml");
    }

};

//-------------------------------------------------------------------------
// 상세
//-------------------------------------------------------------------------
scwin.f_Detail = async function(row, winName) {
    let win_url = "/ui/ds/op/wrkrslts/yardwrkrslts/"+ winName;

    let data = {
          odrNo: ds_emp.getCellData(row, "odrNo")
        , mrn: ds_emp.getCellData(row, "mrn")
        , msn: ds_emp.getCellData(row, "msn")
        , hsn: ds_emp.getCellData(row, "hsn")
        , blNo: ds_emp.getCellData(row, "blNo")
        , wrkPlCd: ds_emp.getCellData(row, "wrkPlCd")
        , wrkPlNm: ds_emp.getCellData(row, "wrkPlNm")
        , cntrBulk: ds_emp.getCellData(row, "cntrBulk")
        , openFlag : "1"
    };

    let opts = {
        id: "smpPop",
        popupName: "세관 반입 신고 등록",
        modal: false,
        type: "browserPopup",
        width: 1200,
        height: 600,
        title: "세관 반입 신고 등록"
    };

    //상세화면 호출 
    let rtnList = await $c.win.openPopup(win_url, opts, data);
}


scwin.ed_blNo_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());    
};

scwin.sbm_retrieve_submit = function (e) {
    if(dma_retrieve.get("crryinoutCls") == "all") {
        dma_retrieve.set("crryinoutCls", "");
    } else {
        dma_retrieve.set("crryinoutCls", acb_crryinoutCls.getValue());
    }

    if(dma_retrieve.get("sndClsCd") == "all") {
        dma_retrieve.set("sndClsCd", "");
    } else {
        dma_retrieve.set("sndClsCd", acb_sndCls.getValue());
    }
};

scwin.ds_emp_onbeforecelldatachange = function (info) {
    if(info.colID == "sndYn"){
        if(ds_emp.getCellData(info.rowIndex, "sndYn") == 1){
            $c.win.alert("전송완료된 데이타는 수정할 수 없습니다.");
            ds_emp.setCellData(info.rowIndex, "sndYn", 1);
            return;
        }
    }
};

scwin.gr_emp_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) return;

    if(columnId == "sndYn"){
        $c.win.alert("ds_emp.getCellData(sndYn) : " + ds_emp.getCellData(rowIndex, "sndYn"));
        debugger;
        if(ds_emp.getCellData(rowIndex, "sndYn") == 1 && ds_emp.getCellData(rowIndex, "sndClsCdNm") != "미전송"){
            $c.win.alert("전송완료된 데이타는 수정할 수 없습니다.");
            ds_emp.setCellData(rowIndex, "sndYn", 1);
            return;
        }
    }
    //반입
    if(ds_emp.getCellData(rowIndex,"crryinoutClsCd") == "I"){       
        scwin.f_Detail(rowIndex, "op_302_01_16b.xml");
        //반출
    } else if(ds_emp.getCellData(rowIndex,"crryinoutClsCd") == "O"){ 
        scwin.f_Detail(rowIndex, "op_302_01_17b.xml");
    }
};


scwin.gr_emp_onviewchange = function (info) {
    if("sndYn"==info.colId ){
        if(ds_emp.getCellData(info.rowIndex, "sndClsCdNm") != "미전송"){
            $c.win.alert("전송완료된 데이타는 수정할 수 없습니다.");
            ds_emp.setCellData(info.rowIndex, "sndYn", 1);
            gr_emp.setCellChecked(info.rowIndex, info.colIndex, false);
            return;
        }
    }
};
